USE LicoresMaduoDB;
GO

-- ── Activity Request catalog tables ──────────────────────────
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'ACTIVITY_TYPE')
    CREATE TABLE ACTIVITY_TYPE    (AT_Id  INT IDENTITY(1,1) NOT NULL, AT_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_ACTIVITY_TYPE PRIMARY KEY (AT_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'BUDGET_ACTIVITIES')
    CREATE TABLE BUDGET_ACTIVITIES (BA_Id INT IDENTITY(1,1) NOT NULL, BA_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_BUDGET_ACTIVITIES PRIMARY KEY (BA_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'DENIAL_REASONS')
    CREATE TABLE DENIAL_REASONS   (DR_Id  INT IDENTITY(1,1) NOT NULL, DR_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_DENIAL_REASONS PRIMARY KEY (DR_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'ENTERTAINMENT_TYPE')
    CREATE TABLE ENTERTAINMENT_TYPE (ET_Id INT IDENTITY(1,1) NOT NULL, ET_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_ENTERTAINMENT_TYPE PRIMARY KEY (ET_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'STATUS_CODES')
    CREATE TABLE STATUS_CODES     (SC_Id  INT IDENTITY(1,1) NOT NULL, SC_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_STATUS_CODES PRIMARY KEY (SC_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'SPONSORING_TYPE')
    CREATE TABLE SPONSORING_TYPE  (ST_Id  INT IDENTITY(1,1) NOT NULL, ST_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_SPONSORING_TYPE PRIMARY KEY (ST_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'FISCAL_YEARS')
    CREATE TABLE FISCAL_YEARS     (FY_Id  INT IDENTITY(1,1) NOT NULL, FY_Year INT NOT NULL, FY_StartDate DATE NULL, FY_EndDate DATE NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_FISCAL_YEARS PRIMARY KEY (FY_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'LICORES_GROUP')
    CREATE TABLE LICORES_GROUP    (LG_Id  INT IDENTITY(1,1) NOT NULL, LG_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_LICORES_GROUP PRIMARY KEY (LG_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'LOCATION_INFO')
    CREATE TABLE LOCATION_INFO    (LI_Id  INT IDENTITY(1,1) NOT NULL, LI_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_LOCATION_INFO PRIMARY KEY (LI_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'POS_CATEGORY')
    CREATE TABLE POS_CATEGORY     (PC_Id  INT IDENTITY(1,1) NOT NULL, PC_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_POS_CATEGORY PRIMARY KEY (PC_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'POS_LEND_GIVE')
    CREATE TABLE POS_LEND_GIVE    (PLG_Id INT IDENTITY(1,1) NOT NULL, PLG_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_POS_LEND_GIVE PRIMARY KEY (PLG_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'POS_MATERIALS_STATUS')
    CREATE TABLE POS_MATERIALS_STATUS (PMS_Id INT IDENTITY(1,1) NOT NULL, PMS_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_POS_MATERIALS_STATUS PRIMARY KEY (PMS_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CUSTOMER_NON_CLIENT')
    CREATE TABLE CUSTOMER_NON_CLIENT  (CNC_Id INT IDENTITY(1,1) NOT NULL, CNC_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CUSTOMER_NON_CLIENT PRIMARY KEY (CNC_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CUSTOMER_SALES_GROUP')
    CREATE TABLE CUSTOMER_SALES_GROUP (CSG_Id INT IDENTITY(1,1) NOT NULL, CSG_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CUSTOMER_SALES_GROUP PRIMARY KEY (CSG_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CUSTOMER_SEGMENT_INFO')
    CREATE TABLE CUSTOMER_SEGMENT_INFO (CSI_Id INT IDENTITY(1,1) NOT NULL, CSI_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CUSTOMER_SEGMENT_INFO PRIMARY KEY (CSI_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CUSTOMER_TARGET_GROUP')
    CREATE TABLE CUSTOMER_TARGET_GROUP (CTG_Id INT IDENTITY(1,1) NOT NULL, CTG_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CUSTOMER_TARGET_GROUP PRIMARY KEY (CTG_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'FACILITATORS_INFO')
    CREATE TABLE FACILITATORS_INFO (FI_Id INT IDENTITY(1,1) NOT NULL, FI_Description NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_FACILITATORS_INFO PRIMARY KEY (FI_Id));
GO

