IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_BOTTLES')
    CREATE TABLE CAT_BOTTLES         (CB_Id  INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_BOTTLES PRIMARY KEY (CB_Id));
