IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_COLORS')
    CREATE TABLE CAT_COLORS          (CC_Id  INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_COLORS PRIMARY KEY (CC_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_CONTENT')
    CREATE TABLE CAT_CONTENT         (CCO_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_CONTENT PRIMARY KEY (CCO_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_COOLER_CAPACITY')
    CREATE TABLE CAT_COOLER_CAPACITY (CCC_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_COOLER_CAPACITY PRIMARY KEY (CCC_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_COOLER_MODEL')
    CREATE TABLE CAT_COOLER_MODEL    (CCM_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_COOLER_MODEL PRIMARY KEY (CCM_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_COOLER_TYPE')
    CREATE TABLE CAT_COOLER_TYPE     (CCTY_Id INT IDENTITY(1,1) NOT NULL, CAT_Prefix NVARCHAR(10) NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_COOLER_TYPE PRIMARY KEY (CCTY_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_FILE_NAMES')
    CREATE TABLE CAT_FILE_NAMES      (CFN_Id INT IDENTITY(1,1) NOT NULL, File_Names NVARCHAR(100) NOT NULL, Display_Text NVARCHAR(100) NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_FILE_NAMES PRIMARY KEY (CFN_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_GENDER')
    CREATE TABLE CAT_GENDER          (CG_Id  INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_GENDER PRIMARY KEY (CG_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_GLASS_SERVING')
    CREATE TABLE CAT_GLASS_SERVING   (CGS_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_GLASS_SERVING PRIMARY KEY (CGS_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_INSURRANCE')
    CREATE TABLE CAT_INSURRANCE      (CI_Id  INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_INSURRANCE PRIMARY KEY (CI_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_LED')
    CREATE TABLE CAT_LED             (CL_Id  INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_LED PRIMARY KEY (CL_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_MAINT_MONTHS')
    CREATE TABLE CAT_MAINT_MONTHS    (CMM_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_MAINT_MONTHS PRIMARY KEY (CMM_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_MATERIALS')
    CREATE TABLE CAT_MATERIALS       (CM_Id  INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_MATERIALS PRIMARY KEY (CM_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_SHAPES')
    CREATE TABLE CAT_SHAPES          (CS2_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_SHAPES PRIMARY KEY (CS2_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_SIZES')
    CREATE TABLE CAT_SIZES           (CSZ_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_SIZES PRIMARY KEY (CSZ_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'CAT_VAP_TYPE')
    CREATE TABLE CAT_VAP_TYPE        (CVT_Id INT IDENTITY(1,1) NOT NULL, CAT_Sel NVARCHAR(100) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_CAT_VAP_TYPE PRIMARY KEY (CVT_Id));
GO

-- ── Aankoopbon tables ─────────────────────────────────────────
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'VENDORS')
    CREATE TABLE VENDORS (
        VND_Id       INT IDENTITY(1,1) NOT NULL,
        VND_Code     NVARCHAR(6)   NOT NULL,
        VND_Name     NVARCHAR(100) NOT NULL,
        VND_Address_1 NVARCHAR(100) NULL,
        VND_Phone_1  NVARCHAR(25)  NULL,
        VND_Email    NVARCHAR(50)  NULL,
        VND_Contact  NVARCHAR(100) NULL,
        VND_CURR     NVARCHAR(3)   NULL,
        VND_CRIB     NVARCHAR(15)  NULL,
        VND_KVK      NVARCHAR(15)  NULL,
        VND_CASH     BIT           NULL,
        IS_Active    BIT           NOT NULL DEFAULT 1,
        Created_At   DATETIME      NOT NULL DEFAULT GETUTCDATE(),
        CONSTRAINT PK_VENDORS PRIMARY KEY (VND_Id),
        CONSTRAINT UQ_VENDORS_Code UNIQUE (VND_Code)
    );
GO

IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'DEPARTMENTS')
    CREATE TABLE DEPARTMENTS (DP_Id INT IDENTITY(1,1) NOT NULL, DP_NAME NVARCHAR(15) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_DEPARTMENTS PRIMARY KEY (DP_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'EENHEDEN')
    CREATE TABLE EENHEDEN (EE_Id INT IDENTITY(1,1) NOT NULL, UnitCode NVARCHAR(10) NOT NULL, Omschrijving NVARCHAR(50) NULL, OmrekenFaktor DECIMAL(18,4) NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_EENHEDEN PRIMARY KEY (EE_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'RECEIVERS')
    CREATE TABLE RECEIVERS (REC_Id INT IDENTITY(1,1) NOT NULL, REC_NAME NVARCHAR(30) NOT NULL, REC_ID_DOC NVARCHAR(15) NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_RECEIVERS PRIMARY KEY (REC_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'REQUESTORS')
    CREATE TABLE REQUESTORS (REQ_Id INT IDENTITY(1,1) NOT NULL, REQ_NAME NVARCHAR(15) NOT NULL, REQ_EMAIL NVARCHAR(50) NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_REQUESTORS PRIMARY KEY (REQ_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'REQUESTORS_VENDOR')
    CREATE TABLE REQUESTORS_VENDOR (RV_Id INT IDENTITY(1,1) NOT NULL, RS_REQUESTOR NVARCHAR(15) NOT NULL, RS_VENDOR NVARCHAR(6) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_REQUESTORS_VENDOR PRIMARY KEY (RV_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'COST_TYPE')
    CREATE TABLE COST_TYPE (CT_Id INT IDENTITY(1,1) NOT NULL, TC_NAME NVARCHAR(15) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_COST_TYPE PRIMARY KEY (CT_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'VEHICLE_TYPE')
    CREATE TABLE VEHICLE_TYPE (VT_Id INT IDENTITY(1,1) NOT NULL, VT_NAME NVARCHAR(15) NOT NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_VEHICLE_TYPE PRIMARY KEY (VT_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'VEHICLES')
    CREATE TABLE VEHICLES (VH_Id INT IDENTITY(1,1) NOT NULL, VH_LICENSE NVARCHAR(10) NOT NULL, VH_TYPE NVARCHAR(15) NULL, VH_MODEL NVARCHAR(15) NULL, IS_Active BIT NOT NULL DEFAULT 1, Created_At DATETIME NOT NULL DEFAULT GETUTCDATE(), CONSTRAINT PK_VEHICLES PRIMARY KEY (VH_Id));
IF NOT EXISTS (SELECT 1 FROM sys.tables WHERE name = 'AB_PRODUCTS')
    CREATE TABLE AB_PRODUCTS (
        ABP_Id      INT IDENTITY(1,1) NOT NULL,
        ItemKode    NVARCHAR(20)  NOT NULL,
        Omschrijving NVARCHAR(100) NULL,
        VendorCode  NVARCHAR(6)   NULL,
        Cost_Type   NVARCHAR(15)  NULL,
        Eenheid     NVARCHAR(10)  NULL,
        IS_Active   BIT           NOT NULL DEFAULT 1,
        Created_At  DATETIME      NOT NULL DEFAULT GETUTCDATE(),
        CONSTRAINT PK_AB_PRODUCTS PRIMARY KEY (ABP_Id)
    );
GO
